class Solution:
    def climbStairs(self, n: int) -> int:
        if n <= 2:
            return n

        # 空间优化：只用两个变量
        prev2, prev1 = 1, 2

        for _ in range(3, n + 1):
            curr = prev1 + prev2
            prev2 = prev1
            prev1 = curr

        return prev1
